            "cover_image": {
                "url": "https://bebbopacific.app/sites/somoa/files/styles/content_1200xh_/public/2024-09/birth-at-a-birthing-center.webp?itok=Toz_NHp5",
                "name": "Birth at a birthing center.jpg",
                "alt": "Woman giving birth at birthing center"
            },
